/**
 * Segment Tree implementation for Range Maximum Query (RMQ) and Point Update.
 * Values in the segment tree represent the maximum score achieved for a given element value.
 */
class SegmentTree {
    constructor(size, initialValue = -Infinity) {
        // Size should be large enough to cover all possible values (1 to V_max)
        this.V = size;
        this.tree = new Array(4 * this.V).fill(initialValue);
        this.initialValue = initialValue;
    }

    // Point Update: Sets the value at a specific index (value) to max(current, newValue)
    update(index, newValue, node = 1, start = 1, end = this.V) {
        if (start === end) {
            // We store the maximum score seen so far for this specific value
            this.tree[node] = Math.max(this.tree[node], newValue);
            return;
        }

        const mid = Math.floor((start + end) / 2);
        if (index <= mid) {
            this.update(index, newValue, 2 * node, start, mid);
        } else {
            this.update(index, newValue, 2 * node + 1, mid + 1, end);
        }

        // Update current node: maximum of children
        this.tree[node] = Math.max(this.tree[2 * node], this.tree[2 * node + 1]);
    }

    // Range Maximum Query (RMQ): Finds max value in range [L, R]
    query(L, R, node = 1, start = 1, end = this.V) {
        // No overlap
        if (R < start || L > end || L > R) {
            return this.initialValue;
        }

        // Complete overlap
        if (L <= start && end <= R) {
            return this.tree[node];
        }

        // Partial overlap
        const mid = Math.floor((start + end) / 2);
        const p1 = this.query(L, R, 2 * node, start, mid);
        const p2 = this.query(L, R, 2 * node + 1, mid + 1, end);

        return Math.max(p1, p2);
    }
}

function solve(nums, k) {
    const n = nums.length;
    if (n === 0) return 0;

    // Max possible value is 10^5. We use 1-based indexing for values.
    const V_MAX = 100000;

    // DP_UP[i]: Max score ending at i, where nums[i] > nums[j] (peak/up turn)
    const dpUp = new Array(n).fill(0);
    // DP_DOWN[i]: Max score ending at i, where nums[i] < nums[j] (valley/down turn)
    const dpDown = new Array(n).fill(0);

    // ST_UP tracks max(DP_UP[j]) for eligible j, indexed by nums[j]
    const stUp = new SegmentTree(V_MAX);
    // ST_DOWN tracks max(DP_DOWN[j]) for eligible j, indexed by nums[j]
    const stDown = new SegmentTree(V_MAX);

    let maxScore = 0;

    for (let i = 0; i < n; i++) {
        const currentVal = nums[i];

        // Step 1: Activate eligible index j = i - K
        // If i >= K, the results from index j = i - K are now eligible for calculation at index i.
        if (i >= k) {
            const j_eligible = i - k;
            const val_j = nums[j_eligible];

            // Update STs using the DP results calculated for j_eligible
            // Note: We use Math.max to ensure we only store the highest score for that value
            stUp.update(val_j, dpUp[j_eligible]);
            stDown.update(val_j, dpDown[j_eligible]);
        }

        // Step 2: Calculate DP[i] using current STs (which contain results from j <= i-K)

        // Calculate DP_UP[i]: Needs previous element j such that nums[j] < nums[i]
        // We query ST_DOWN (which stores scores ending in a DOWN turn) for values < currentVal.
        // Range: [1, currentVal - 1]
        let maxPrevDown = stDown.query(1, currentVal - 1);

        // If maxPrevDown is -Infinity (no valid predecessor found), we start a new sequence (score 0).
        dpUp[i] = currentVal + Math.max(0, maxPrevDown);


        // Calculate DP_DOWN[i]: Needs previous element j such that nums[j] > nums[i]
        // We query ST_UP (which stores scores ending in an UP turn) for values > currentVal.
        // Range: [currentVal + 1, V_MAX]
        let maxPrevUp = stUp.query(currentVal + 1, V_MAX);

        // If maxPrevUp is -Infinity, start a new sequence.
        dpDown[i] = currentVal + Math.max(0, maxPrevUp);

        // Step 3: Update overall max score
        maxScore = Math.max(maxScore, dpUp[i], dpDown[i]);
    }

    return maxScore;
}

