using namespace std;

// Define a suitable representation for negative infinity for long long scores
const long long INF = LLONG_MIN / 2; // Using LLONG_MIN / 2 to avoid overflow during summation

class SegmentTree {
private:
    int V;
    vector<long long> tree;
    long long initialValue;

    void update_recursive(int index, long long newValue, int node, int start, int end) {
        if (start == end) {
            // We store the maximum score seen so far for this specific value index
            tree[node] = max(tree[node], newValue);
            return;
        }

        int mid = start + (end - start) / 2;
        if (index <= mid) {
            update_recursive(index, newValue, 2 * node, start, mid);
        } else {
            update_recursive(index, newValue, 2 * node + 1, mid + 1, end);
        }

        // Update current node: maximum of children
        tree[node] = max(tree[2 * node], tree[2 * node + 1]);
    }

    long long query_recursive(int L, int R, int node, int start, int end) {
        // No overlap
        if (R < start || L > end || L > R) {
            return initialValue;
        }

        // Complete overlap
        if (L <= start && end <= R) {
            return tree[node];
        }

        // Partial overlap
        int mid = start + (end - start) / 2;
        long long p1 = query_recursive(L, R, 2 * node, start, mid);
        long long p2 = query_recursive(L, R, 2 * node + 1, mid + 1, end);

        return max(p1, p2);
    }

public:
    // Size represents the maximum possible value (1 to Size)
    SegmentTree(int size, long long initialValue = INF) : V(size), initialValue(initialValue) {
        // We need space for 4*V nodes for a full binary tree implementation
        tree.assign(4 * V + 1, initialValue);
    }

    // Point Update: Sets the value at a specific index (value) to max(current, newValue)
    void update(int index, long long newValue) {
        // Index must be within bounds [1, V]
        if (index < 1 || index > V) return;
        update_recursive(index, newValue, 1, 1, V);
    }

    // Range Maximum Query (RMQ): Finds max value in range [L, R]
    long long query(int L, int R) {
        if (L > R) return initialValue;
        // Clamp range to valid segment tree bounds
        L = max(1, L);
        R = min(V, R);
        if (L > R) return initialValue;

        return query_recursive(L, R, 1, 1, V);
    }
};


