            }
            if (dpDown[j_eligible] > 0) {
                stDown.update((int)val_j, dpDown[j_eligible]);
            }
        }

        // --- Calculate DP[i] ---

        // Case 1: DP_UP[i] (nums[i] is a peak, requires previous valley j such that nums[j] < nums[i])
        // Query ST_DOWN for values in range [1, currentVal - 1]
        long long maxPrevDown = stDown.query(1, (int)currentVal - 1);

        // If maxPrevDown is INF, no valid predecessor found. Start new sequence of length 1.
        // If maxPrevDown > 0, we extend the sequence.
        long long extension = max(0LL, maxPrevDown);
        dpUp[i] = currentVal + extension;


        // Case 2: DP_DOWN[i] (nums[i] is a valley, requires previous peak j such that nums[j] > nums[i])
        // Query ST_UP for values in range [currentVal + 1, V_MAX]
        long long maxPrevUp = stUp.query((int)currentVal + 1, V_MAX);

        // If maxPrevUp is INF, no valid predecessor found. Start new sequence of length 1.
        long long extension2 = max(0LL, maxPrevUp);
        dpDown[i] = currentVal + extension2;

        // Step 3: Update overall max score
        maxScore = max({maxScore, dpUp[i], dpDown[i]});
    }

    return maxScore;
